// Template app.js — Struktur minimal yang harus bisa ditulis dari memori

// === DOM ELEMENTS ===
const articleForm  = document.getElementById('articleForm');
const inputTitle   = document.getElementById('inputTitle');
const inputContent = document.getElementById('inputContent');
const tableBody    = document.getElementById('tableBody');
const modalOverlay = document.getElementById('modalOverlay');
const toastNotif   = document.getElementById('toastNotif');

// === STATE ===
let articles = [];

// === RENDER ===
function renderTable() {
  tableBody.innerHTML = '';
  if (articles.length === 0) {
    tableBody.innerHTML = '<tr><td colspan="4">Belum ada data.</td></tr>';
    return;
  }
  articles.forEach((a, i) => {
    const tr = document.createElement('tr');
    tr.innerHTML = `<td>${i+1}</td><td>${a.title}</td><td>${a.content}</td>
      <td>
        <button onclick="setupEdit(${a.id})">Edit</button>
        <button onclick="deleteArticle(${a.id})">Hapus</button>
      </td>`;
    tableBody.appendChild(tr);
  });
}

// === UTILITIES ===
function clearForm()  { inputTitle.value = ''; inputContent.value = ''; }
function openModal()  { modalOverlay.classList.add('active');    }
function closeModal() { modalOverlay.classList.remove('active'); }
function showToast(msg, type = 'success') {
  toastNotif.textContent = msg;
  toastNotif.className = `toast ${type} show`;
  setTimeout(() => toastNotif.classList.remove('show'), 2500);
}

// === CRUD ===
articleForm.addEventListener('submit', e => {
  e.preventDefault();
  const title   = inputTitle.value.trim();
  const content = inputContent.value.trim();
  if (!title || !content) { showToast('Isi semua field!', 'error'); return; }
  articles.push({ id: Date.now(), title, content });
  renderTable(); clearForm(); showToast('Artikel disimpan!');
});

function deleteArticle(id) {
  articles = articles.filter(a => a.id !== id);
  renderTable(); showToast('Artikel dihapus!');
}

// === INIT ===
renderTable();
